remediation.terraform:
resource "aws_ebs_encryption_by_default" "<example_resource_name>" {
  enabled = true  # Critical: enables default EBS encryption in this region
}

resource "aws_ebs_snapshot_block_public_access" "<example_resource_name>" {
  state = "block-all-sharing" # CRITICAL: Blocks all public sharing of EBS snapshots in this Region
}

resource "aws_ebs_snapshot_copy" "<example_resource_name>" {
  source_snapshot_id = "<UNENCRYPTED_SNAPSHOT_ID>"
  source_region      = "<SOURCE_REGION>"
  encrypted          = true  # Critical: creates an encrypted copy of the snapshot to remediate the finding
}

# Encrypted EBS volume
resource "aws_ebs_volume" "<example_resource_name>" {
  availability_zone = "<example_az>"
  size              = 1
  encrypted         = true  # CRITICAL: ensures the volume is created encrypted
}

# Create a snapshot for an existing EBS volume
resource "aws_ebs_snapshot" "<example_resource_name>" {
  volume_id = "<example_resource_id>" # Critical: creating this snapshot makes the volume pass the check
}

# Minimal AWS Backup plan protecting all EBS volumes
resource "aws_backup_plan" "<example_resource_name>" {
  name = "<example_resource_name>"

  rule {
    rule_name         = "<example_rule_name>"
    target_vault_name = "Default"
  }
}

resource "aws_backup_selection" "<example_resource_name>" {
  name         = "<example_resource_name>"
  plan_id      = aws_backup_plan.<example_resource_name>.id
  iam_role_arn = "arn:aws:iam::<example_account_id>:role/service-role/AWSBackupDefaultServiceRole"

  resources = [
    "arn:aws:ec2:*:*:volume/*" # Critical: selects all EBS volumes to satisfy the check
  ]
}
